 ></v-text-field>\r\n                      <v-text-field\r\n                          v-show=\"isEngTab\"\r\n                          v-model=\"postNameEng\"\r\n                          :label=\"$t('PromotionEvent.Create.form.post_name')\"\r\n                          :rules=\"[$myValidator.SimpleValidate($t('Validate.required'))]\"\r\n                          outlined\r\n                          required\r\n\r\n                      ></v-text-field>\r\n\r\n\r\n\r\n                      <v-dialog\r\n\r\n                          ref=\"dialogStart\"\r\n                          v-model=\"modalStart\"\r\n                          :return-value.sync=\"dateStart\"\r\n                          persistent\r\n                          width=\"290px\"\r\n                      >\r\n                        <template v-slot:activator=\"{ on, attrs }\">\r\n                          <v-text-field\r\n                              v-show=\"tab == 0\"\r\n                              v-model=\"dateStart\"\r\n                              :label=\"$t('PromotionEvent.Create.form.start_date')\"\r\n                              :rules=\"[$myValidator.SimpleValidate($t('Validate.required'))]\"\r\n\r\n                              outlined\r\n                              prepend-inner-icon=\"mdi-calendar\"\r\n                              readonly\r\n\r\n                              v-bind=\"attrs\"\r\n                              v-on=\"on\"\r\n                          ></v-text-field>\r\n                        </template>\r\n                        <v-date-picker\r\n                            v-model=\"dateStart\"\r\n                            locale=\"lo-LA\"\r\n                            scrollable\r\n                        >\r\n                          <v-spacer></v-spacer>\r\n                          <v-btn\r\n                              color=\"primary\"\r\n                              text\r\n                              @click=\"modalStart = false\"\r\n       