                         :rules=\"[$myValidator.SimpleValidate($t('Validate.required'))]\"\r\n\r\n                              outlined\r\n                              prepend-inner-icon=\"mdi-calendar\"\r\n                              readonly\r\n\r\n                              v-bind=\"attrs\"\r\n                              v-on=\"on\"\r\n                          ></v-text-field>\r\n                        </template>\r\n                        <v-date-picker\r\n                            v-model=\"dateEnd\"\r\n                            locale=\"lo-LA\"\r\n                            scrollable\r\n                        >\r\n                          <v-spacer></v-spacer>\r\n                          <v-btn\r\n                              color=\"primary\"\r\n                              text\r\n                              @click=\"modalEnd = false\"\r\n                          >\r\n                            Cancel\r\n                          </v-btn>\r\n                          <v-btn\r\n                              color=\"primary\"\r\n                              text\r\n                              @click=\"$refs.dialogEnd[0].save(dateEnd)\"\r\n                          >\r\n                            OK\r\n                          </v-btn>\r\n                        </v-date-picker>\r\n                      </v-dialog>\r\n\r\n                      <v-select\r\n                          v-show=\"tab == 0\"\r\n                          v-model=\"statusValue\"\r\n                          :items=\"$t('PromotionEvent.status.item')\"\r\n                          :label=\"$t('PromotionEvent.Create.form.status')\"\r\n\r\n                          :rules=\"[$myValidator.SimpleValidate($t('Validate.required'))]\"\r\n                          item-text=\"text\"\r\n                          item-value=\"value\"\r\n                          outlined\r\n                          required\r\n\r\n                      ></v-select>\r\n\r\n\r\n                      <vue-editor  v-show=\"isLaoTab\" v-model=\"descriptionText\" id=\"editor1\" :editor-toolbar=\"customToolbar\"  class=\"mb-10\" ref=\"editor1\" />\r\n\r\n                      <vue-editor v-show=\"isEngTab\" v-model=\"descriptionTextEng\" id=\"editor2\" :editor-toolbar=\"customToolbar\" class=\"mb-10\" ref=\"editor2\" />\r\n\r\n\r\n                      <div v-show=\"isLaoTab\">\r\n\r\n                        <div v-if=\"previewImage[0] == null\" class=\"upload-image\">\r\n\r\n                          <div class=\"content\">\r\n                            <i class=\"fas fa-plus-circle\"></i>\r\n                            <h3>{{ $t(\"PromotionEvent.Create.form.picture\") }}</h3>\r\n                          </div>\r\n                          <input\r\n                              accept=\"image/*\"\r\n\r\n                              class=\"choose-file\"\r\n                              multiple\r\n                              name=\"upload-image\"\r\n                              type=\"file\"\r\n                              @change=\"UploadImage\"\r\n                          />\r\n                        </div>\r\n\r\n\r\n                        <div v-else class=\"image\">\r\n                          <v-carousel height=\"100%\">\r\n                            <v-carousel-item v-for=\"(imageFiles,index) in previewImage\" :key=\"index\">\r\n                              <div class=\"increase-decrease-image\">\r\n                                <v-btn\r\n                                    class=\"mx-2\"\r\n                                    color=\"primary\"\r\n                                    dark\r\n                                    fab\r\n                                    small\r\n                                    @click=\"removeImage(index)\"\r\n                                >\r\n                                  <v-icon dark>\r\n                                    mdi-minus\r\n                                  </v-icon>\r\n                                </v-btn>\r\n\r\n\r\n                                <v-btn\r\n                                    class=\"mx-2\"\r\n                                    color=\"success\"\r\n                                    dark\r\n                                    fab\r\n                                    small\r\n                                    @click=\"onIncreaseImage\"\r\n                                >\r\n                                  <v-icon dark>\r\n                                    mdi-plus\r\n                                  </v-icon>\r\n                                </v-btn>\r\n                                <input\r\n                                    ref=\"uploader\"\r\n\r\n                                    accept=\"image/*\"\r\n                                    class=\"d-none\"\r\n                                    multiple\r\n                                    type=\"file\"\r\n                                    @change=\"UploadImage\"\r\n                                />\r\n                              </div>\r\n                              <v-layout row>\r\n                                <v-flex v-for=\"j in 1\" :key=\"j\" align-self-center>\r\n\r\n                                  <img :src=\"imageFiles\" class=\"image-files\">\r\n\r\n                                </v-flex>\r\n\r\n                              </v-layout>\r\n                            </v-carousel-item>\r\n                          </v-carousel>\r\n\r\n                        </div>\r\n                      </div>\r\n\r\n                      <div v-show=\"isEngTab\">\r\n\r\n                        <div v-if=\"previewImageEng[0] == null\" class=\"upload-image\">\r\n\r\n                          <div class=\"content\">\r\n                            <i class=\"fas fa-plus-circle\"></i>\r\n                            <h3>{{ $t(\"PromotionEvent.Create.form.picture\") }}</h3>\r\n                          </div>\r\n                          <input\r\n                              accept=\"image/*\"\r\n\r\n                              class=\"choose-file\"\r\n                              multiple\r\n                              name=\"upload-image\"\r\n                              type=\"file\"\r\n                              @change=\"UploadImageEng\"\r\n                          />\r\n                        </div>\r\n\r\n\r\n                        <div v-else class=\"image\">\r\n                          <v-carousel height=\"100%\">\r\n                            <v-carousel-item v-for=\"(imageFilesEng,index) in previewImageEng\" :key=\"index\">\r\n                              <div class=\"increase-decrease-image\">\r\n                                <v-btn\r\n                                    class=\"mx-2\"\r\n                                    color=\"primary\"\r\n                                    dark\r\n                                    fab\r\n                                    small\r\n                                    @click=\"removeImageEng(index)\"\r\n                                >\r\n                                  <v-icon dark>\r\n                                    mdi-minus\r\n                                  </v-icon>\r\n                                </v-btn>\r\n\r\n\r\n                                <v-btn\r\n                                    class=\"mx-2\"\r\n                                    color=\"success\"\r\n                                    dark\r\n                                    fab\r\n                                    small\r\n                                    @click=\"onIncreaseImageEng\"\r\n                                >\r\n                                  <v-icon dark>\r\n                                    mdi-plus\r\n                                  </v-icon>\r\n                                </v-btn>\r\n                                <input\r\n                                    ref=\"uploaderEng\"\r\n\r\n                                    accept=\"image/*\"\r\n                                    class=\"d-none\"\r\n                                    multiple\r\n                                    type=\"file\"\r\n                                    @change=\"UploadImageEng\"\r\n                                />\r\n                              </div>\r\n                              <v-layout row>\r\n                                <v-flex v-for=\"j in 1\" :key=\"j\" align-self-center>\r\n\r\n                                  <img :src=\"imageFilesEng\" class=\"image-files\">\r\n\r\n                                </v-flex>\r\n\r\n                              </v-layout>\r\n                            </v-carousel-item>\r\n                          </v-carousel>\r\n\r\n                        </div>\r\n                      </div>\r\n                    </v-form>\r\n                    <div class=\"form-actions\">\r\n                      <v-btn class=\"mx-5\" plain @click=\"reset\">{{\r\n                          $t(\"PromotionEvent.Create.form.button.cancel\")\r\n                        }}\r\n                      </v-btn>\r\n                      <v-btn :disabled=\"!valid\" class=\"btn btn-create\" @click=\"submitForm\">\r\n                        {{ $t(\"PromotionEvent.Create.form.button.save\") }}\r\n                      </v-btn\r\n                      >\r\n                    </div>\r\n                  </div>\r\n                </div>\r\n              </v-tab-item>\r\n            </v-tabs-items>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n  </div>\r\n</template>\r\n\r\n<script>\r\nimport {mapActions, mapGetters} from 'vuex'\r\nimport { VueEditor } from \"vue2-editor\";\r\nexport default {\r\n  name: \"Create\",\r\n  components: { VueEditor },\r\n  data() {\r\n    return {\r\n      cate_post_item:0,\r\n      descriptionText:this.$i18n.t('Post.Create.form.description'),\r\n      descriptionTextEng:this.$i18n.t('Post.Create.form.description'),\r\n      isLaoTab: false,\r\n      isEngTab: false,\r\n      postName: '',\r\n      postNameEng: '',\r\n      statusValue: '',\r\n      catePostValue: '',\r\n      uploadImage: [],\r\n      uploadImageEng: [],\r\n      tab: null,\r\n      previewImage: [],\r\n      previewImageEng: [],\r\n      valid: true,\r\n\r\n      dateStart: (new Date(Date.now() - (new Date()).getTimezoneOffset() * 60000)).toISOString().substr(0, 10),\r\n      dateEnd: (new Date(Date.now() - (new Date()).getTimezoneOffset() * 60000)).toISOString().substr(0, 10),\r\n\r\n\r\n      modalStart: false,\r\n      modalEnd: false,\r\n      customToolbar : [\r\n        [{ 'font': [] }],\r\n        [{ 'header': [false, 1, 2, 3, 4, 5, 6, ] }],\r\n        [{ 'size': ['small', false, 'large', 'huge'] }],\r\n        ['bold', 'italic', 'underline', 'strike'],\r\n        [{'align': ''}, {'align': 'center'}, {'align': 'right'}, {'align': 'justify'}],\r\n        [{ 'header': 1 }, { 'header': 2 }],\r\n        ['blockquote', 'code-block'],\r\n        [{ 'list': 'ordered'}, { 'list': 'bullet' }],\r\n        [{ 'script': 'sub'}, { 'script': 'super' }],\r\n        [{ 'indent': '-1'}, { 'indent': '+1' }],\r\n        [{ 'color': [] }, { 'background': [] }],\r\n        // ['link', 'image', 'video', 'formula'],\r\n        [{ 'direction': 'rtl' }],\r\n        ['clean'],\r\n      ]\r\n    };\r\n  },\r\n\r\n  created() {\r\n\r\n\r\n\r\n  },\r\n  mounted() {\r\n    this.checkTabLang('ລາວ')\r\n\r\n\r\n\r\n  },\r\n\r\n  methods: {\r\n\r\n    checkTabLang(lang) {\r\n      console.log(lang)\r\n      if (lang == 'ລາວ' || lang == 'Lao') {\r\n        this.isLaoTab = true\r\n        this.isEngTab = false\r\n        console.log(\"lao\" + this.isLaoTab)\r\n        console.log(this.isEngTab)\r\n      } else {\r\n        this.isLaoTab = false\r\n        this.isEngTab = true\r\n        console.log(\"lao\" + this.isLaoTab)\r\n        console.log(this.isEngTab)\r\n      }\r\n    },\r\n\r\n\r\n    onIncreaseImage() {\r\n\r\n      this.$refs.uploader[0].click()\r\n    },\r\n    onIncreaseImageEng() {\r\n\r\n      this.$refs.uploaderEng[0].click()\r\n    },\r\n\r\n\r\n    UploadImage(e) {\r\n      console.log('e')\r\n      console.log(e)\r\n      console.log('e.target.files')\r\n      console.log(e.target.files)\r\n      const img = e.target.files;\r\n\r\n      for (let i = 0; i < img.length; i++) {\r\n\r\n        this.uploadImage.push(img[i])\r\n        const reader = new FileReader();\r\n        reader.readAsDataURL(img[i]);\r\n        reader.onload = (e) => {\r\n          console.log(e);\r\n          this.previewImage.push(e.target.result);\r\n          console.log(this.previewImage[i]);\r\n        }\r\n\r\n      }\r\n      ;\r\n    },\r\n\r\n    UploadImageEng(e) {\r\n\r\n      const img = e.target.files;\r\n\r\n      for (let i = 0; i < img.length; i++) {\r\n        this.uploadImageEng.push(img[i])\r\n        const reader = new FileReader();\r\n        reader.readAsDataURL(img[i]);\r\n        reader.onload = (e) => {\r\n\r\n          this.previewImageEng.push(e.target.result);\r\n          console.log(this.previewImageEng[i]);\r\n        }\r\n\r\n      }\r\n      ;\r\n    },\r\n\r\n    removeImage(index) {\r\n      this.uploadImage.splice(index, 1);\r\n      this.previewImage.splice(index, 1);\r\n    },\r\n    removeImageEng(index) {\r\n      this.uploadImageEng.splice(index, 1);\r\n      this.previewImageEng.splice(index, 1);\r\n    },\r\n\r\n    submitForm() {\r\n      this.$refs.form[0].validate();\r\n      if (this.$refs.form[0].validate()) {\r\n\r\n        this.createPromotionEvent({\r\n\r\n\r\n          'title': this.postName,\r\n          'description': this.descriptionText,\r\n          'status': this.statusValue,\r\n          'start_date': this.dateStart,\r\n          'end_date': this.dateEnd,\r\n          'other_lang_title': this.postNameEng,\r\n          'other_lang_description': this.descriptionTextEng,\r\n\r\n          'avatar': this.uploadImage,\r\n          'avatar_EN': this.uploadImageEng\r\n        })\r\n        console.log('create successful')\r\n      } else {\r\n        console.log('can not create')\r\n      }\r\n    },\r\n    reset() {\r\n      this.$router.back();\r\n      this.$refs.form[0].reset();\r\n    },\r\n\r\n    ...mapActions({\r\n\r\n      createPromotionEvent: 'PromotionEvent/createPromotionEvent'\r\n\r\n    })\r\n  },\r\n\r\n  computed: {}\r\n};\r\n</script>\r\n\r\n<style lang=\"scss\" scoped>\r\n\r\n\r\n.post-form {\r\n  .form-title {\r\n    width: 100%;\r\n    padding: 0.5rem 0;\r\n\r\n    h1 {\r\n      font-size: 1.5rem;\r\n      font-weight: 400;\r\n      text-transform: uppercase;\r\n    }\r\n  }\r\n\r\n  .lang-select-input {\r\n    width: 100%;\r\n    padding: 1rem 0;\r\n\r\n    .tab-content {\r\n      width: 100%;\r\n      padding: 2rem 0;\r\n\r\n      .card-form {\r\n        width: 100%;\r\n        padding: 0.5rem;\r\n        display: flex;\r\n        justify-content: center;\r\n        align-items: center;\r\n\r\n        .form-content {\r\n          width: 70%;\r\n\r\n\r\n          .upload-image {\r\n            width: 100%;\r\n            height: 300px;\r\n            border-radius: 0.3rem;\r\n            position: relative;\r\n            overflow: hidden;\r\n            object-fit: cover;\r\n            transition: all ease 0.5s;\r\n            border: 1px solid $gray-color;\r\n\r\n\r\n            .content {\r\n              position: absolute;\r\n              left: 0;\r\n              right: 0;\r\n              top: 45%;\r\n              margin: auto;\r\n              text-align: center;\r\n\r\n              i.fa-plus-circle {\r\n                font-size: 2rem;\r\n                color: $black-color;\r\n              }\r\n            }\r\n\r\n            .choose-file {\r\n              position: absolute;\r\n              left: 0;\r\n              right: 0;\r\n              top: 0;\r\n              margin: auto;\r\n              text-align: center;\r\n              z-index: 1;\r\n              width: 100%;\r\